import re, glob, os

root = '/app/pyknotid/pyknotid'
files = []
for ext in ('*.py','*.pyx','*.pxd'):
    for dp,_,fns in os.walk(root):
        for fn in fns:
            if fn.endswith(('.py','.pyx','.pxd')):
                files.append(os.path.join(dp,fn))
files = sorted(set(files))

# deprecated numpy scalar aliases -> python builtins / replacements
repl = {'float':'float','int':'int','bool':'bool','complex':'complex',
        'object':'object','str':'str','long':'int','unicode':'str'}
prefixes = ['np','numpy','n']
changed = {}
for f in files:
    s = open(f).read()
    orig = s
    for pre in prefixes:
        for alias,new in repl.items():
            # match prefix.alias not followed by identifier char (so np.float64 untouched)
            pat = re.compile(r'\b'+pre+r'\.'+alias+r'(?![0-9A-Za-z_])')
